"use client";

import { useState, useMemo, useRef, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Network, Search, Filter, ZoomIn, ZoomOut, Download, Users, Briefcase, ChevronRight, MapPin, CheckCircle, ExternalLink, Info, Target as TargetIcon, Zap, ArrowUpRight, X } from "lucide-react";
import dynamic from 'next/dynamic';
import { useRouter } from "next/navigation";
import Link from "next/link";

// Dynamically import force graph to avoid SSR issues
const ForceGraph2D = dynamic(() => import('react-force-graph-2d'), { ssr: false });

// --- Mock Data ---
const graphData = {
  nodes: [
    { id: 'JD', name: 'John Doe', type: 'internal', role: 'Partner', color: '#6366f1' },
    { id: 'AS', name: 'Alice Smith', type: 'internal', role: 'Associate', color: '#6366f1' },
    { id: 'MB', name: 'Marc Berenson', type: 'target', role: 'CEO, Aetherial SA', color: '#10b981' },
    { id: 'TW', name: 'Thomas Wright', type: 'target', role: 'Founder, TechFlow', color: '#10b981' },
    { id: 'SJ', name: 'Sarah Jenkins', type: 'advisor', role: 'MD, Lazard', color: '#f59e0b' },
    { id: 'RJ', name: 'Robert Jones', type: 'advisor', role: 'Partner, PwC', color: '#f59e0b' },
    { id: 'AL', name: 'Alice Laurent', type: 'target', role: 'CFO, NexSphere', color: '#10b981' },
  ],
  links: [
    { source: 'JD', target: 'MB', label: 'Board Overlap', value: 3 },
    { source: 'JD', target: 'SJ', label: 'Former Colleague', value: 2 },
    { source: 'SJ', target: 'MB', label: 'Lead Advisor', value: 5 },
    { source: 'AS', target: 'TW', label: 'Alumni Network', value: 1 },
    { source: 'AS', target: 'AL', label: 'Relationship Path', value: 2 },
    { source: 'MB', target: 'AL', label: 'Industry Peer', value: 1 },
    { source: 'RJ', target: 'TW', label: 'Tax Advisory', value: 4 },
  ]
};

export default function RelationshipGraph() {
  const [selectedNode, setSelectedNode] = useState<any>(graphData.nodes[2]); // Default to Marc
  const [search, setSearch] = useState("");
  const fgRef = useRef<any>(null);
  const router = useRouter();

  // Filter nodes based on search
  const filteredData = useMemo(() => {
    if (!search) return graphData;
    const nodes = graphData.nodes.filter(n => n.name.toLowerCase().includes(search.toLowerCase()));
    const nodeIds = new Set(nodes.map(n => n.id));
    const links = graphData.links.filter(l => nodeIds.has(l.source as string) || nodeIds.has(l.target as string));
    return { nodes, links };
  }, [search]);

  return (
    <div className="flex flex-col h-[calc(100vh-4rem)] w-full max-w-7xl mx-auto pb-4 px-4 overflow-hidden">
      {/* Header */}
      <header className="flex flex-col lg:flex-row lg:items-end justify-between gap-6 mb-6 pt-4">
        <div>
          <h1 className="text-3xl md:text-4xl font-black tracking-tight text-white mb-2 flex items-center gap-4">
            <div className="p-2 rounded-2xl bg-indigo-500/10 border border-indigo-500/20">
              <Network size={24} className="text-indigo-400" />
            </div>
            Network Intelligence
          </h1>
          <p className="text-gray-400 text-sm font-medium">
            Proprietary relationship mapping identifying warm entry paths.
          </p>
        </div>

        <div className="flex flex-col sm:flex-row gap-3">
          <div className="relative group w-full sm:w-80">
            <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-500 group-focus-within:text-indigo-400 transition-colors">
               <Search size={18} />
            </span>
            <input 
               type="text" 
               value={search}
               onChange={(e) => setSearch(e.target.value)}
               placeholder="Search nodes..." 
               className="w-full bg-white/[0.03] border border-white/10 rounded-2xl py-3 pl-12 pr-4 text-sm text-gray-200 placeholder-gray-600 outline-none focus:border-indigo-500/50 focus:bg-white/[0.05] transition-all"
            />
          </div>
          <button className="px-5 py-3 rounded-2xl bg-white/[0.03] border border-white/10 text-sm font-bold text-white hover:bg-white/10 transition-all flex items-center justify-center gap-2">
            <Filter size={18} /> <span className="sm:hidden lg:inline">Depth</span>
          </button>
        </div>
      </header>

      {/* Main content grid */}
      <div className="flex-1 grid grid-cols-1 lg:grid-cols-4 gap-8 min-h-0">

        {/* Graph Area */}
        <div className="lg:col-span-3 rounded-[2.5rem] bg-[#050505] border border-white/10 relative overflow-hidden flex flex-col group shadow-[0_4px_50px_rgba(0,0,0,0.8)] backdrop-blur-xl">
          {/* Legend */}
          <div className="absolute top-4 sm:top-6 left-4 sm:left-6 z-10 flex flex-col gap-2 sm:gap-3">
             <div className="px-3 py-1.5 sm:px-4 sm:py-2 rounded-xl sm:rounded-2xl bg-black/60 border border-white/10 backdrop-blur-md text-[8px] sm:text-[10px] uppercase font-black tracking-widest text-gray-400 flex items-center gap-2 sm:gap-3">
                <div className="w-1.5 h-1.5 sm:w-2 sm:h-2 rounded-full bg-[#6366f1] animate-pulse" /> Team
             </div>
             <div className="px-3 py-1.5 sm:px-4 sm:py-2 rounded-xl sm:rounded-2xl bg-black/60 border border-white/10 backdrop-blur-md text-[8px] sm:text-[10px] uppercase font-black tracking-widest text-gray-400 flex items-center gap-2 sm:gap-3">
                <div className="w-1.5 h-1.5 sm:w-2 sm:h-2 rounded-full bg-[#10b981]" /> Target
             </div>
             <div className="px-3 py-1.5 sm:px-4 sm:py-2 rounded-xl sm:rounded-2xl bg-black/60 border border-white/10 backdrop-blur-md text-[8px] sm:text-[10px] uppercase font-black tracking-widest text-gray-400 flex items-center gap-2 sm:gap-3">
                <div className="w-1.5 h-1.5 sm:w-2 sm:h-2 rounded-full bg-[#f59e0b]" /> Advisor
             </div>
          </div>

          <div className="absolute top-4 sm:top-6 right-4 sm:right-6 z-10 flex flex-col gap-2">
             <button onClick={() => fgRef.current?.zoomToFit(400)} className="w-8 h-8 sm:w-10 sm:h-10 rounded-xl sm:rounded-2xl bg-black/60 border border-white/10 flex items-center justify-center text-gray-400 hover:text-white hover:bg-white/10 transition-all">
                <Download size={18} />
             </button>
          </div>

          {/* Real Graph Component */}
          <div className="flex-1 w-full h-full">
            <ForceGraph2D
              ref={fgRef}
              graphData={filteredData}
              backgroundColor="#050505"
              nodeLabel="name"
              nodeColor={node => (node as any).color}
              nodeRelSize={7}
              linkColor={() => "rgba(255,255,255,0.08)"}
              linkWidth={link => (link as any).value}
              onNodeClick={(node) => setSelectedNode(node)}
              nodeCanvasObject={(node: any, ctx, globalScale) => {
                const label = node.name;
                const fontSize = 12 / globalScale;
                ctx.font = `${fontSize}px Inter, sans-serif`;
                const textWidth = ctx.measureText(label).width;
                const bckgDimensions = [textWidth, fontSize].map(n => n + fontSize * 0.5);

                // Draw circle
                ctx.beginPath();
                ctx.arc(node.x, node.y, 6, 0, 2 * Math.PI, false);
                ctx.fillStyle = node.color;
                ctx.fill();

                // Active ring
                if (selectedNode?.id === node.id) {
                  ctx.beginPath();
                  ctx.arc(node.x, node.y, 9, 0, 2 * Math.PI, false);
                  ctx.strokeStyle = node.color;
                  ctx.lineWidth = 2 / globalScale;
                  ctx.stroke();
                }

                ctx.textAlign = 'center';
                ctx.textBaseline = 'middle';
                ctx.fillStyle = 'rgba(255,255,255,0.8)';
                ctx.font = `bold ${fontSize}px sans-serif`;
                ctx.fillText(label, node.x, node.y + 12);
              }}
            />
          </div>

          <div className="absolute bottom-6 left-6 z-10">
             <div className="px-4 py-2 rounded-2xl bg-indigo-500/10 border border-indigo-500/20 backdrop-blur-md text-[10px] tracking-widest uppercase font-black text-indigo-400 flex items-center gap-2">
                <Info size={14} /> Intelligence Overlay Active: 14M Overlaps
             </div>
          </div>
        </div>

        {/* Node Detail Sidebar / Overlay */}
        <AnimatePresence mode="wait">
          {selectedNode && (
            <motion.div 
              key={selectedNode?.id}
              initial={{ opacity: 0, x: 20, y: 100 }}
              animate={{ opacity: 1, x: 0, y: 0 }}
              exit={{ opacity: 0, y: 100 }}
              className="fixed lg:relative bottom-6 sm:bottom-10 left-4 right-4 lg:bottom-0 lg:left-0 lg:right-0 lg:col-span-1 rounded-[2rem] sm:rounded-[2.5rem] bg-black/80 lg:bg-black/40 border border-white/10 backdrop-blur-3xl p-6 sm:p-8 flex flex-col max-h-[50vh] lg:max-h-full overflow-y-auto shadow-2xl space-y-6 sm:space-y-8 z-[60]"
            >
              <div className="flex items-center justify-between lg:hidden mb-2">
                <span className="text-[10px] font-black text-gray-600 uppercase tracking-widest">Entity Intel</span>
                <button onClick={() => setSelectedNode(null)} className="p-2 rounded-lg bg-white/5 text-gray-500"><X size={16} /></button>
              </div>
                <div className="space-y-4">
                  <div className="w-16 h-16 rounded-[1.5rem] bg-indigo-500/10 border border-indigo-500/20 flex items-center justify-center text-white font-black text-2xl shadow-[0_0_20px_rgba(99,102,241,0.2)]">
                    {selectedNode.name.split(' ').map((n: any) => n[0]).join('')}
                  </div>
                  <div>
                    <h2 className="text-2xl font-black text-white leading-tight tracking-tighter">{selectedNode.name}</h2>
                    <p className="text-indigo-400 text-[10px] font-black uppercase tracking-widest mt-1 opacity-80">{selectedNode.role}</p>
                  </div>
                </div>

                <div className="grid grid-cols-2 gap-3">
                   <div className="p-4 rounded-3xl bg-white/[0.03] border border-white/5 space-y-1">
                      <div className="text-[9px] font-black text-gray-600 uppercase tracking-widest">Strength</div>
                      <div className="text-sm font-black text-white">84% Path</div>
                   </div>
                   <div className="p-4 rounded-3xl bg-white/[0.03] border border-white/5 space-y-1">
                      <div className="text-[9px] font-black text-gray-600 uppercase tracking-widest">Context</div>
                      <div className="text-sm font-black text-white">Market-Direct</div>
                   </div>
                </div>

                <div className="space-y-4">
                  <h3 className="text-[10px] font-black text-gray-600 uppercase tracking-[0.2em]">Contact Metadata</h3>
                  <div className="space-y-3">
                    <div className="flex items-center gap-4 text-sm">
                      <div className="w-8 h-8 rounded-xl bg-white/5 flex items-center justify-center text-gray-500"><MapPin size={16} /></div>
                      <span className="text-gray-300 font-bold">Paris, France</span>
                    </div>
                    <div className="flex items-center gap-4 text-sm">
                      <div className="w-8 h-8 rounded-xl bg-white/5 flex items-center justify-center text-gray-500"><Briefcase size={16} /></div>
                      <span className="text-gray-300 font-bold">Industry Concentration: Industrial Tech</span>
                    </div>
                  </div>
                </div>

                <div className="space-y-4">
                   <h3 className="text-[10px] font-black text-gray-600 uppercase tracking-[0.2em]">AI Path Intelligence</h3>
                   <div className="p-4 rounded-3xl bg-indigo-500/5 border border-indigo-500/10 flex gap-3">
                      <Zap size={18} className="text-indigo-400 shrink-0" />
                      <p className="text-xs text-gray-400 leading-relaxed font-medium">
                        Strong proximity via <span className="text-white font-bold">Lazard advisory board</span>. Berenson attended the same Executive Forum as John Doe in 2023.
                      </p>
                   </div>
                </div>

                <div className="pt-6 mt-auto">
                  <Link href={`/targets/${selectedNode.id}/report`} className="w-full py-4 rounded-[1.5rem] bg-white text-black font-black text-xs uppercase tracking-widest hover:bg-indigo-50 transition-all shadow-[0_10px_30px_rgba(0,0,0,0.2)] flex items-center justify-center gap-3">
                     Generate Dossier <ArrowUpRight size={18} />
                  </Link>
                </div>
            </motion.div>
          )}
        </AnimatePresence>

      </div>
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { TrendingUp, Users, Building, AlertTriangle, ArrowRight, Zap, ChevronRight, MessageSquare, Target as TargetIcon, Activity, ShieldCheck, Cpu, Radio, Sparkles } from "lucide-react";
import { useRouter } from "next/navigation";
import { SkeletonCard, SkeletonKPI } from "@/components/LoadingSkeleton";

import { Target } from "@/types";

const API_URL = process.env.NEXT_PUBLIC_API_URL || "";

export default function Home() {
  const [targets, setTargets] = useState<Target[]>([]);
  const [loading, setLoading] = useState(true);
  const [fetchError, setFetchError] = useState(false);
  const [processingAction, setProcessingAction] = useState<string | null>(null);
  const [notification, setNotification] = useState<string | null>(null);
  const router = useRouter();

  useEffect(() => {
    if (notification) {
      const timer = setTimeout(() => setNotification(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [notification]);

  const handleAction = (name: string, message: string) => {
    setProcessingAction(name);
    setTimeout(() => {
      setProcessingAction(null);
      setNotification(message);
    }, 1500);
  };

  // Fetch targets from FastAPI backend
  useEffect(() => {
    fetch(`${API_URL}/api/targets`)
      .then(res => {
        if (!res.ok) throw new Error(`HTTP error: ${res.status}`);
        return res.json();
      })
      .then(data => {
        setTargets(data.data);
        setLoading(false);
      })
      .catch(err => {
        console.error("Failed to fetch targets:", err);
        setFetchError(true);
        setLoading(false);
      });
  }, []);

  return (
    <div className="flex flex-col gap-10 w-full max-w-7xl mx-auto py-4 relative">
       {/* Toast Notification */}
       <AnimatePresence>
        {notification && (
          <motion.div 
            initial={{ opacity: 0, y: 50, x: '-50%' }}
            animate={{ opacity: 1, y: 0, x: '-50%' }}
            exit={{ opacity: 0, y: 20, x: '-50%' }}
            className="fixed bottom-10 left-1/2 z-[200] px-6 py-3 rounded-2xl bg-indigo-600 text-white font-black text-[10px] uppercase tracking-widest shadow-2xl flex items-center gap-3 border border-indigo-400 backdrop-blur-xl"
          >
            <ShieldCheck size={16} /> {notification}
          </motion.div>
        )}
      </AnimatePresence>
      {/* Header */}
      <header className="flex flex-col md:flex-row md:items-end justify-between gap-6 shrink-0">
        <div>
          <h1 className="text-5xl font-black tracking-tighter text-white mb-3 flex items-center gap-5">
            EDRCF Engine
            <div className="flex items-center gap-2.5 px-4 py-1.5 rounded-full bg-indigo-500/10 border border-indigo-500/20 text-[10px] text-indigo-400 font-black uppercase tracking-[0.2em]">
               <Radio size={14} className="animate-pulse" /> Intelligence Live
            </div>
          </h1>
          <p className="text-gray-400 text-lg font-medium max-w-2xl leading-relaxed">
            Proprietary origination control center. Calibrating <span className="text-white">short-term transaction windows</span> and relationship proximity in real-time.
          </p>
        </div>
        
        <div className="flex flex-col sm:flex-row gap-4 w-full md:w-auto">
          <button 
            onClick={() => handleAction('diag', 'System diagnostics completed. All clusters operational.')}
            className="px-6 py-3 rounded-2xl bg-white/[0.03] border border-white/10 text-[11px] font-black uppercase tracking-widest text-white hover:bg-white/10 transition-all flex items-center justify-center gap-3 backdrop-blur-md"
          >
            {processingAction === 'diag' ? (
               <div className="w-4 h-4 border-2 border-indigo-500/20 border-t-indigo-500 rounded-full animate-spin" />
            ) : (
               <Activity size={16} className="text-indigo-500" />
            )}
            <span className="hidden sm:inline">{processingAction === 'diag' ? 'Running...' : 'System Diagnostics'}</span>
          </button>
          <button 
            onClick={() => handleAction('recal', 'Force recalibration initiated. Intelligence scores updated.')}
            className="px-6 py-3 rounded-2xl bg-indigo-600 text-white shadow-[0_20px_40px_rgba(79,70,229,0.3)] hover:bg-indigo-500 transition-all flex items-center justify-center gap-3 font-black text-[11px] uppercase tracking-widest active:scale-95"
          >
            {processingAction === 'recal' ? (
               <div className="w-4 h-4 border-2 border-white/20 border-t-white rounded-full animate-spin" />
            ) : (
               <Sparkles size={16} />
            )}
            {processingAction === 'recal' ? 'Recalibrating...' : 'Force Recalibration'}
          </button>
        </div>
      </header>

      {/* KPI Section */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        {loading
          ? Array.from({ length: 4 }).map((_, i) => <SkeletonKPI key={i} />)
          : [
              { icon: Building, label: "Active Monitored", value: "2,408", trend: "+12%", color: "text-indigo-400" },
              { icon: AlertTriangle, label: "System Triggers", value: "45", trend: "+5", color: "text-amber-500" },
              { icon: Users, label: "Rel. Proximity", value: "891", trend: "+24", color: "text-purple-400" },
              { icon: TrendingUp, label: "Predicted M&A", value: "18", trend: "-2", color: "text-indigo-400" },
            ].map((card, idx) => (
              <motion.div
                initial={{ opacity: 0, y: 15 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: idx * 0.1, duration: 0.5 }}
                key={card.label}
                className="p-8 rounded-[2.5rem] bg-black/40 border border-white/10 backdrop-blur-2xl group hover:border-indigo-500/40 transition-all shadow-2xl relative overflow-hidden"
              >
                <div className="absolute top-0 right-0 p-6 opacity-[0.02] group-hover:opacity-[0.05] transition-opacity">
                   <card.icon size={80} />
                </div>
                <div className="flex justify-between items-start mb-8 relative z-10">
                  <div className={`p-3.5 rounded-2xl bg-white/5 border border-white/10 ${card.color}`}>
                    <card.icon size={24} />
                  </div>
                  <span className={`text-[10px] font-black px-2.5 py-1 rounded-xl border ${
                    card.trend.startsWith('+') ? 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20' : 'bg-rose-500/10 text-rose-400 border-rose-500/20'
                  }`}>
                    {card.trend}
                  </span>
                </div>
                <div className="text-4xl font-black text-white mb-2 tracking-tighter relative z-10">{card.value}</div>
                <div className="text-[10px] font-black text-gray-500 uppercase tracking-widest relative z-10">{card.label}</div>
              </motion.div>
            ))
        }
      </div>

      {/* Main Grid */}
      <div className="grid grid-cols-1 lg:grid-cols-12 gap-10 items-start">
        
        {/* Targets Feed */}
        <div className="lg:col-span-8 flex flex-col gap-6">
          <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center mb-6 gap-4">
            <h2 className="text-xs font-black text-white uppercase tracking-[0.3em] flex items-center gap-4">
              <div className="hidden sm:block w-1.5 h-6 bg-indigo-600 rounded-full shadow-[0_0_15px_rgba(79,70,229,0.5)]" /> 
              High Confidence Origination Trajectories
            </h2>
            <button onClick={() => router.push("/targets")} className="w-full sm:w-auto text-[10px] font-black text-indigo-400 hover:text-indigo-300 uppercase tracking-widest transition-colors flex items-center justify-center gap-2 bg-indigo-500/5 px-5 py-2.5 rounded-2xl border border-indigo-500/10 hover:border-indigo-500/30">
              Intelligence Vault <ChevronRight size={16} />
            </button>
          </div>

          {fetchError && (
             <motion.div 
               initial={{ opacity: 0, scale: 0.95 }}
               animate={{ opacity: 1, scale: 1 }}
               className="p-8 rounded-[2.5rem] bg-rose-500/5 border border-rose-500/20 text-rose-300 flex items-center gap-6"
             >
                <div className="w-14 h-14 rounded-2xl bg-rose-500/10 flex items-center justify-center border border-rose-500/20 shadow-2xl">
                   <AlertTriangle size={28} className="text-rose-500" />
                </div>
                <div>
                   <div className="font-black uppercase tracking-widest text-xs mb-1 text-rose-500">Connectivity Error</div>
                   <div className="text-sm font-medium text-gray-400">Unable to establish secure tunnel to EDRCF Internal Services. Verify host status.</div>
                </div>
             </motion.div>
          )}

          <div className="flex flex-col gap-5">
            {loading
              ? Array.from({ length: 3 }).map((_, i) => <SkeletonCard key={i} />)
              : targets.slice(0, 3).map((target, idx) => (
              <motion.div 
                onClick={() => router.push(`/targets/${target.id}`)}
                initial={{ opacity: 0, x: -10 }}
                animate={{ opacity: 1, x: 0 }}
                transition={{ delay: 0.2 + idx * 0.1 }}
                key={target.id}
                className="group p-10 rounded-[3rem] bg-black/40 border border-white/10 hover:border-indigo-500/40 transition-all cursor-pointer relative overflow-hidden backdrop-blur-3xl shadow-2xl active:scale-[0.99]"
              >
                <div className="flex justify-between items-start relative z-10">
                  <div className="flex-1">
                    <div className="flex items-center gap-5 mb-5">
                      <div className="w-16 h-16 rounded-[1.5rem] bg-white/5 border border-white/10 flex items-center justify-center text-gray-400 group-hover:text-indigo-400 group-hover:bg-indigo-500/10 group-hover:border-indigo-500/30 transition-all shadow-xl">
                         <Building size={28} />
                      </div>
                      <div>
                        <h3 className="text-3xl font-black text-white tracking-tighter group-hover:text-indigo-400 transition-colors">{target.name}</h3>
                        <div className="flex gap-3 items-center mt-2">
                          <span className="px-3 py-1 rounded-xl text-[10px] font-black tracking-widest uppercase bg-indigo-500/10 text-indigo-400 border border-indigo-500/20">
                            {target.sector}
                          </span>
                          <span className="text-[10px] font-black text-gray-600 uppercase tracking-[0.2em]">{target.id}</span>
                        </div>
                      </div>
                    </div>
                    
                    <div className="flex flex-wrap gap-3 mt-8">
                      {target.topSignals.map((signal) => (
                        <div key={signal.id} className="px-4 py-2 rounded-2xl bg-white/[0.03] text-gray-400 text-xs font-black uppercase tracking-widest flex items-center gap-2.5 border border-white/5 group-hover:bg-white/[0.05] transition-all">
                          <div className="w-2 h-2 rounded-full bg-indigo-500/50 shadow-[0_0_8px_rgba(79,70,229,0.5)]" />
                          {signal.label}
                        </div>
                      ))}
                    </div>
                  </div>
                  
                  <div className="flex flex-col items-end">
                    <span className="text-7xl font-black text-white leading-none tracking-tighter bg-clip-text text-transparent bg-gradient-to-b from-white to-gray-800">
                      {target.globalScore}
                    </span>
                    <span className="text-[10px] uppercase tracking-[0.4em] text-indigo-400/80 font-black mt-3">
                      Score Global
                    </span>
                  </div>
                </div>

                <div className="mt-10 pt-8 border-t border-white/[0.05] flex flex-col md:flex-row justify-between items-start md:items-center gap-6 relative z-10">
                  <div className="flex gap-8 sm:gap-12">
                    <div className="space-y-1.5">
                      <span className="text-[10px] font-black text-gray-600 uppercase tracking-widest block">Type Probable</span>
                      <span className="text-base text-gray-200 font-bold tracking-tight">{target.analysis.type}</span>
                    </div>
                    <div className="space-y-1.5">
