                      animate={{ strokeDashoffset: 2 * Math.PI * 115 * (1 - targetData.globalScore / 100) }}
                      transition={{ duration: 1.5, ease: "easeOut" }}
                      cx="128" cy="128" r="115" 
                      stroke="url(#gradient-radar)" 
